import{_ as t,o as a,c as s,ag as d}from"./chunks/framework.DFmy_ALI.js";const u=JSON.parse('{"title":"Trusted Merchant-Hosted Checkout","description":"","frontmatter":{},"headers":[],"relativePath":"guide/trusted-merchant-hosted.md","filePath":"guide/trusted-merchant-hosted.md"}'),o={name:"guide/trusted-merchant-hosted.md"};function n(r,e,i,c,h,l){return a(),s("div",null,[...e[0]||(e[0]=[d(`<h1 id="trusted-merchant-hosted-checkout" tabindex="-1">Trusted Merchant-Hosted Checkout <a class="header-anchor" href="#trusted-merchant-hosted-checkout" aria-label="Permalink to &quot;Trusted Merchant-Hosted Checkout&quot;">​</a></h1><p>Trusted merchant-hosted checkout lets an approved merchant keep the customer fully inside the merchant website or app. There is no OpenWave redirect, popup, iframe, or embedded page for this path.</p><p>This is not the default direct integration model. The default model is <strong>Hosted Checkout via Merchant API</strong>, where the merchant backend creates a session and the customer completes payment in OpenWave-hosted checkout.</p><h2 id="when-this-is-allowed" tabindex="-1">When this is allowed <a class="header-anchor" href="#when-this-is-allowed" aria-label="Permalink to &quot;When this is allowed&quot;">​</a></h2><p>Astro must explicitly enable trusted merchant-hosted checkout for the merchant. Live traffic also requires:</p><ul><li>live environment enabled</li><li>direct API access enabled</li><li>a live merchant key or live channel key</li><li>at least one active managed webhook endpoint</li><li>approved browser origins for frontend calls, unless the merchant proxies every checkout call through its backend</li></ul><h2 id="api-sequence" tabindex="-1">API sequence <a class="header-anchor" href="#api-sequence" aria-label="Permalink to &quot;API sequence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Step</th><th>Caller</th><th>Endpoint</th></tr></thead><tbody><tr><td>Create trusted session</td><td>Merchant backend</td><td><code>POST /api/v1/payments/initiate</code></td></tr><tr><td>Exchange browser token</td><td>Merchant backend</td><td><code>POST /api/v1/payments/sessions/{session_id}/merchant-checkout/access</code></td></tr><tr><td>Resolve payer</td><td>Merchant frontend or backend proxy</td><td><code>POST /api/v1/payments/sessions/{session_id}/merchant-checkout/resolve-payer</code></td></tr><tr><td>Start phone lookup</td><td>Merchant frontend or backend proxy</td><td><code>POST /api/v1/payments/sessions/{session_id}/merchant-checkout/phone/start</code></td></tr><tr><td>Verify phone OTP</td><td>Merchant frontend or backend proxy</td><td><code>POST /api/v1/payments/sessions/{session_id}/merchant-checkout/phone/verify</code></td></tr><tr><td>Select phone account</td><td>Merchant frontend or backend proxy</td><td><code>POST /api/v1/payments/sessions/{session_id}/merchant-checkout/phone/select</code></td></tr><tr><td>Select bank auth</td><td>Merchant frontend or backend proxy</td><td><code>POST /api/v1/payments/sessions/{session_id}/merchant-checkout/select-auth</code></td></tr><tr><td>Submit bank OTP</td><td>Merchant frontend or backend proxy</td><td><code>POST /api/v1/payments/sessions/{session_id}/merchant-checkout/confirm</code></td></tr><tr><td>Poll push</td><td>Merchant frontend or backend proxy</td><td><code>GET /api/v1/payments/sessions/{session_id}/merchant-checkout/push-status</code></td></tr><tr><td>Read current state</td><td>Merchant frontend or backend proxy</td><td><code>GET /api/v1/payments/sessions/{session_id}/merchant-checkout/status</code></td></tr></tbody></table><p>All endpoints after <code>/access</code> are under:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/api/v1/payments/sessions/{session_id}/merchant-checkout</span></span></code></pre></div><h2 id="required-headers" tabindex="-1">Required headers <a class="header-anchor" href="#required-headers" aria-label="Permalink to &quot;Required headers&quot;">​</a></h2><p>Session creation and access exchange use the merchant key on the backend:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Authorization</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Bearer mk_live_...</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Idempotency-Key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merchant-order-reference</span></span></code></pre></div><p>Trusted checkout browser calls use the session token:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Origin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://merchant.example</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">X-Session-Token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;merchant_checkout_session_token&gt;</span></span></code></pre></div><p>The <code>Origin</code> must match an allowed merchant origin configured in Astro.</p><h2 id="frontend-and-backend-split" tabindex="-1">Frontend and backend split <a class="header-anchor" href="#frontend-and-backend-split" aria-label="Permalink to &quot;Frontend and backend split&quot;">​</a></h2><p>The merchant backend may:</p><ul><li>store merchant API keys</li><li>create payment sessions</li><li>exchange trusted sessions into short-lived checkout tokens</li><li>perform server-side status checks</li><li>receive and verify signed webhooks</li></ul><p>The merchant frontend may:</p><ul><li>collect payer alias, IBAN, or phone number</li><li>collect bank OTP only for this trusted lane</li><li>call trusted merchant-hosted checkout endpoints with <code>X-Session-Token</code></li><li>show masked account choices from verified phone lookup</li><li>show progress while waiting for webhook-backed fulfilment</li></ul><p>The merchant frontend must not:</p><ul><li>store long-lived merchant keys</li><li>store OTP values after submission</li><li>simulate bank approval locally</li><li>fulfil an order from browser state alone</li></ul><h2 id="status-and-next-action" tabindex="-1">Status and next action <a class="header-anchor" href="#status-and-next-action" aria-label="Permalink to &quot;Status and next action&quot;">​</a></h2><p>Trusted checkout responses include <code>next_action</code> and may include <code>next_action_details</code>. Use those fields to drive the merchant UI instead of guessing state transitions.</p><p>Common actions:</p><table tabindex="0"><thead><tr><th><code>next_action</code></th><th>Merchant UI behavior</th></tr></thead><tbody><tr><td><code>EXCHANGE_MERCHANT_CHECKOUT_ACCESS</code></td><td>Backend must call <code>/merchant-checkout/access</code>.</td></tr><tr><td><code>RESOLVE_PAYER</code></td><td>Ask customer for alias, IBAN, or phone.</td></tr><tr><td><code>VERIFY_PHONE</code></td><td>Ask for phone OTP and show masked choices after verification.</td></tr><tr><td><code>SELECT_AUTH</code></td><td>Show allowed bank authorization methods.</td></tr><tr><td><code>SUBMIT_OTP</code></td><td>Ask for the bank OTP.</td></tr><tr><td><code>POLL_PUSH_STATUS</code></td><td>Poll <code>/push-status</code>.</td></tr><tr><td><code>POLL_PAYMENT_STATUS</code></td><td>Poll <code>/status</code> or wait for webhook.</td></tr><tr><td><code>PAYMENT_COMPLETED</code></td><td>Wait for signed webhook before fulfilment if not already recorded.</td></tr></tbody></table><h2 id="error-handling" tabindex="-1">Error handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error handling&quot;">​</a></h2><p>Show merchant-safe errors only. Do not expose raw bank or CBS text to customers.</p><table tabindex="0"><thead><tr><th>Code</th><th>Meaning</th></tr></thead><tbody><tr><td><code>INVALID_OTP</code></td><td>The OTP was not accepted.</td></tr><tr><td><code>SESSION_EXPIRED</code></td><td>The checkout session expired.</td></tr><tr><td><code>SESSION_INVALID_STATE</code></td><td>The requested step is not valid for the current session.</td></tr><tr><td><code>PAYER_RESOLUTION_FAILED</code></td><td>The payer could not be resolved.</td></tr><tr><td><code>IDEMPOTENCY_CONFLICT</code></td><td>The idempotency key was reused with different request data.</td></tr><tr><td><code>BANK_UNAVAILABLE</code></td><td>The bank is temporarily unavailable.</td></tr></tbody></table><h2 id="fulfilment-rule" tabindex="-1">Fulfilment rule <a class="header-anchor" href="#fulfilment-rule" aria-label="Permalink to &quot;Fulfilment rule&quot;">​</a></h2><p><code>payment.completed</code> remains the authoritative completion signal. Status polling helps the customer experience, but fulfilment must be backed by a signed webhook or a server-side final status lookup that the merchant records durably.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="./ezone-quickstart.html">Ezone Quick Start</a></li><li><a href="./direct-integration.html">Direct Merchant Integration</a></li><li><a href="./webhooks.html">Webhooks</a></li><li><a href="./testing.html">Testing &amp; Sandbox</a></li></ul>`,34)])])}const k=t(o,[["render",n]]);export{u as __pageData,k as default};
